resource "aws_s3_bucket" "terraform_state" {
  bucket = "${local.name_prefix}-tf-state"
  tags   = local.tags
}

resource "aws_ssm_parameter" "app_config" {
  name  = local.config_parameter_name
  type  = "String"
  value = "{\"environment\":\"${var.environment}\"}"
  tags  = local.tags
}

provider "aws" {
  region = var.aws_region

